import "./radio-group.css";

import { RadioGroup } from "radix-ui";
import { cn } from "tailwind-variants";

import { RadioGroupContext } from "./radio-group.context";
import { radioGroupVariants } from "./radio-group.variants";

export type RadioGroupRootProps = React.ComponentProps<typeof RadioGroup.Root>;

export const RadioGroupRoot = ({ className, ...props }: RadioGroupRootProps) => {
  const slots = radioGroupVariants();

  return (
    <RadioGroupContext value={{ slots }}>
      <RadioGroup.Root className={cn(slots.root(), className)} {...props} />
    </RadioGroupContext>
  );
};

import { Circle } from "lucide-react";
import { RadioGroup } from "radix-ui";
import { cn } from "tailwind-variants";

import { useRadioGroupContext } from "./radio-group.context";

export type RadioGroupItemProps = React.ComponentProps<typeof RadioGroup.Item>;

export const RadioGroupItem = ({ className, ...props }: RadioGroupItemProps) => {
  const { slots } = useRadioGroupContext();

  return (
    <RadioGroup.Item className={cn(slots.item(), className)} {...props}>
      <RadioGroup.Indicator className={slots.indicator()}>
        <Circle />
      </RadioGroup.Indicator>
    </RadioGroup.Item>
  );
};

import { createContext, useContext } from "react";

import { radioGroupVariants } from "./radio-group.variants";

export type RadioGroupContext = {
  slots: ReturnType<typeof radioGroupVariants>;
};

export const RadioGroupContext = createContext<null | RadioGroupContext>(null);

export const useRadioGroupContext = () => {
  const context = useContext(RadioGroupContext);
  if (!context) {
    throw new Error("useRadioGroupContext must be used within a RadioGroup");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const radioGroupVariants = tv({
  slots: {
    indicator: "radio-group__indicator",
    item: "radio-group__item",
    root: "radio-group",
  },
});

export type RadioGroupVariants = VariantProps<typeof radioGroupVariants>;

.radio-group {
  @apply grid gap-2;
}

.radio-group__item {
  @apply border-primary text-primary aspect-square size-4 rounded-full border;

  &:hover {
    @apply bg-accent;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply cursor-not-allowed opacity-50;
  }
}

.radio-group__indicator {
  @apply flex items-center justify-center;

  & svg {
    @apply size-2.5 fill-current;
  }
}

import { RadioGroupItem } from "./radio-group-item";
import { RadioGroupRoot } from "./radio-group-root";

export const RadioGroup = {
  Item: RadioGroupItem,
  Root: RadioGroupRoot,
};

export { RadioGroupItem, RadioGroupRoot };

export type { RadioGroupItemProps } from "./radio-group-item";

export type { RadioGroupRootProps } from "./radio-group-root";

export { RadioGroupContext, useRadioGroupContext } from "./radio-group.context";
export { type RadioGroupVariants, radioGroupVariants } from "./radio-group.variants";
